package com.example.myapp;

import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class DeepLinkActivity extends AppCompatActivity {

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        handleDeepLink(getIntent());
        finish();
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        handleDeepLink(intent);
        finish();
    }

    private void handleDeepLink(Intent intent) {
        if (intent == null) {
            navigateToHome();
            return;
        }

        Uri uri = intent.getData();
        if (uri == null) {
            navigateToHome();
            return;
        }

        if (!"myapp".equalsIgnoreCase(uri.getScheme())) {
            navigateToHome();
            return;
        }

        String host = uri.getHost();
        String firstPath = getPathSegment(uri, 0);
        String secondPath = getPathSegment(uri, 1);

        if ("profile".equalsIgnoreCase(host) || "profile".equalsIgnoreCase(firstPath)) {
            String userId = "profile".equalsIgnoreCase(host) ? firstPath : secondPath;
            if (userId != null && !userId.isEmpty()) {
                navigateToProfile(userId);
                return;
            }
        }

        if ("payment".equalsIgnoreCase(host) || "payment".equalsIgnoreCase(firstPath)) {
            String action = "payment".equalsIgnoreCase(host) ? firstPath : secondPath;
            if ("confirm".equalsIgnoreCase(action)) {
                navigateToPaymentConfirm();
                return;
            }
        }

        if ("admin".equalsIgnoreCase(host) || "admin".equalsIgnoreCase(firstPath)) {
            String section = "admin".equalsIgnoreCase(host) ? firstPath : secondPath;
            if ("settings".equalsIgnoreCase(section)) {
                navigateToAdminSettings();
                return;
            }
        }

        navigateToHome();
    }

    @Nullable
    private String getPathSegment(Uri uri, int index) {
        if (uri == null) return null;
        if (uri.getPathSegments() == null || uri.getPathSegments().size() <= index) return null;
        return uri.getPathSegments().get(index);
    }

    private void navigateToProfile(String userId) {
        Intent intent = new Intent(this, ProfileActivity.class);
        intent.putExtra(ProfileActivity.EXTRA_USER_ID, userId);
        startActivity(intent);
    }

    private void navigateToPaymentConfirm() {
        Intent intent = new Intent(this, PaymentConfirmActivity.class);
        startActivity(intent);
    }

    private void navigateToAdminSettings() {
        Intent intent = new Intent(this, AdminSettingsActivity.class);
        startActivity(intent);
    }

    private void navigateToHome() {
        Intent intent = new Intent(this, HomeActivity.class);
        startActivity(intent);
    }
}

